async (params, browser) => {
  // Open Trello
  await browser.open('https://trello.com')

  // Let Trello load
  await browser.wait(2000)

  // Add comment via Trello API
  const result = await browser.evaluate(`const resp = await fetch('/1/cards/' + params.card_id + '/actions/comments?text=' + encodeURIComponent(params.comment), { method: 'POST', credentials: 'same-origin' }); if (!resp.ok) { const err = await resp.text(); throw new Error('Comment failed: ' + resp.status + ' ' + err); } const result = await resp.json(); return { success: true, card_id: '' + params.card_id + '', comment_id: result.id, author: result.memberCreator?.fullName || '' }`)

  return result
}
